 3→function createPartBase(type, overrides = {}) {
 4→  return {
 5→    id: generateId('part'),
 6→    type,
 7→    name: overrides.name || type,
 8→    assemblyId: overrides.assemblyId || null,
 9→    parentId: overrides.parentId || null,
10→    position: { x: 0, y: 0, z: 0, ...overrides.position },
11→    rotation: { x: 0, y: 0, z: 0, ...overrides.rotation },
12→    fill: overrides.fill ?? 'rgba(184, 134, 11, 0.06)',
13→    stroke: overrides.stroke ?? '#1E2433',
14→    strokeWidth: overrides.strokeWidth ?? 2,
15→    ...overrides,
16→  };
17→}
18→
19→export function createPanel(overrides = {}) {
20→  return createPartBase('panel', {
21→    name: 'Panel',
22→    width: 600,
23→    depth: 400,
24→    thickness: 18,
25→    material: 'plywood',
26→    ...overrides,
27→  });
28→}
