52→export function createCutout(overrides = {}) {
53→  if (!overrides.parentId) throw new Error('Cutout requires a parentId');
54→  return createPartBase('cutout', {
55→    name: 'Cutout',
56→    width: 100,
57→    height: 50,
58→    depth: 18,
59→    offsetX: 0,
60→    offsetY: 0,
61→    ...overrides,
62→  });
63→}
