65→export function createHole(overrides = {}) {
66→  if (!overrides.parentId) throw new Error('Hole requires a parentId');
67→  return createPartBase('hole', {
68→    name: 'Hole',
69→    diameter: 35,
70→    depth: 18,
71→    offsetX: 0,
72→    offsetY: 0,
73→    ...overrides,
74→  });
