 1→import { generateId } from '@/domain/ids';
 2→
 3→export function createAssembly(name = 'Untitled Assembly', overrides = {}) {
 4→  return {
 5→    id: generateId('asm'),
 6→    name,
 7→    description: overrides.description || '',
 8→    category: overrides.category || 'general',
 9→    partIds: overrides.partIds || [],
10→    ...overrides,
11→  };
12→}
13→
14→export function addPartToAssembly(assembly, partId) {
15→  if (assembly.partIds.includes(partId)) return assembly;
16→  return { ...assembly, partIds: [...assembly.partIds, partId] };
17→}
18→
19→export function removePartFromAssembly(assembly, partId) {
20→  return { ...assembly, partIds: assembly.partIds.filter((id) => id !== partId) };
21→}
