173→function SketchInner() {
174→  const { project, isDirty, dispatch } = useSketch();
175→  const { maximizedPanel, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
176→  const [showLoadModal, setShowLoadModal] = useState(false);
177→  const [fileHandle, setFileHandle] = useState(null);
178→
179→  // Autosave
180→  useSketchAutosave(project, isDirty, dispatch);
181→
182→  // beforeunload warning
183→  useEffect(() => {
184→    const handler = (e) => {
185→      if (isDirty) {
186→        e.preventDefault();
187→        e.returnValue = '';
188→      }
189→    };
190→    window.addEventListener('beforeunload', handler);
191→    return () => window.removeEventListener('beforeunload', handler);
192→  }, [isDirty]);
193→
194→  // Ctrl+S file save
195→  useEffect(() => {
196→    const handler = async (e) => {
197→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
198→        e.preventDefault();
199→        try {
200→          const result = await exportSketchProjectFile(project, { fileHandle });
201→          if (result.fileHandle) setFileHandle(result.fileHandle);
202→          await saveSketchProject(project);
203→          dispatch({ type: 'MARK_SAVED' });
204→        } catch (err) {
205→          if (!isFilePickerAbortError(err)) {
206→            console.error('Save failed:', err);
207→          }
208→        }
209→      }
210→    };
211→    window.addEventListener('keydown', handler);
212→    return () => window.removeEventListener('keydown', handler);
213→  }, [project, fileHandle, dispatch]);
214→
215→  // If active sheet was deleted, revert to model mode
216→  useEffect(() => {
217→    if (workspaceMode === 'sheet' && activeSheetId) {
218→      const sheetExists = (project.sheets || []).some((s) => s.id === activeSheetId);
219→      if (!sheetExists) {
220→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
221→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
222→      }
223→    }
224→  }, [workspaceMode, activeSheetId, project.sheets, editorDispatch]);
225→
226→  const handleNew = useCallback(() => {
227→    if (isDirty && !window.confirm('You have unsaved changes. Start a new project?')) return;
228→    dispatch({ type: 'SKETCH_NEW' });
229→    setFileHandle(null);
230→  }, [isDirty, dispatch]);
231→
232→  const handleSave = useCallback(async () => {
233→    try {
234→      const result = await exportSketchProjectFile(project, { fileHandle });
235→      if (result.fileHandle) setFileHandle(result.fileHandle);
236→      await saveSketchProject(project);
237→      dispatch({ type: 'MARK_SAVED' });
238→    } catch (err) {
239→      if (!isFilePickerAbortError(err)) {
240→        console.error('Save failed:', err);
241→      }
242→    }
243→  }, [project, fileHandle, dispatch]);
244→
245→  const handleLoadClick = useCallback(() => {
246→    setShowLoadModal(true);
247→  }, []);
248→
249→  const isSheetMode = workspaceMode === 'sheet';
250→
251→  return (
252→    <SketchProjectContext.Provider value={{ handleNew, handleSave, handleLoadClick, fileHandle, setFileHandle }}>
253→      <div className={styles.layout}>
254→        <div className={styles.toolbar}>
255→          <SketchToolbar />
256→        </div>
257→        <div className={styles.sidebar}>
258→          <SketchSidebar />
259→        </div>
260→        <div className={styles.canvas}>
261→          {isSheetMode ? (
262→            <Suspense fallback={<div className={styles.previewFallback}>Loading sheet...</div>}>
263→              <SketchSheetCanvas />
264→            </Suspense>
265→          ) : (
266→            <div className={`${styles.modelWorkspace} ${maximizedPanel ? styles.workspaceMaximized : ''}`}>
267→              {maximizedPanel !== 'preview' && (
268→                <div className={styles.primaryCanvas}>
269→                  <SketchCanvas />
270→                </div>
271→              )}
272→              {maximizedPanel !== 'canvas' && (
273→                <div className={styles.preview}>
274→                  <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
275→                    <SketchPreviewPanel
276→                      isMaximized={maximizedPanel === 'preview'}
277→                      onToggleMaximize={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'preview' })}
278→                    />
279→                  </Suspense>
280→                </div>
281→              )}
282→            </div>
283→          )}
284→        </div>
285→        <div className={styles.rightPanel}>
286→          <SketchPropertiesPanel />
287→        </div>
288→      </div>
289→      {showLoadModal && <SketchLoadModal onClose={() => setShowLoadModal(false)} />}
290→    </SketchProjectContext.Provider>
291→  );
292→}
