  4→const SketchEditorContext = createContext(null);
  5→
  6→function sketchEditorReducer(state, action) {
  7→  switch (action.type) {
  8→    case 'SET_TOOL':
  9→      return {
 10→        ...state,
 11→        activeTool: action.tool,
 12→        toolState: {},
 13→        selectedId: null,
 14→        selectedType: null,
 15→      };
 16→
 17→    case 'SELECT_OBJECT':
 18→      return {
 19→        ...state,
 20→        selectedId: action.id,
 21→        selectedType: action.objectType,
 22→      };
 23→
 24→    case 'DESELECT':
 25→      return {
 26→        ...state,
 27→        selectedId: null,
 28→        selectedType: null,
 29→      };
 30→
 31→    case 'UPDATE_TOOL_STATE':
 32→      return {
 33→        ...state,
 34→        toolState: { ...state.toolState, ...action.payload },
 35→      };
 36→
 37→    case 'SET_VIEWPORT': {
 38→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 39→      return {
 40→        ...state,
 41→        [vpKey]: { ...action.viewport },
 42→      };
 43→    }
 44→
 45→    case 'PAN': {
 46→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 47→      return {
 48→        ...state,
 49→        [vpKey]: {
 50→          ...state[vpKey],
 51→          panX: state[vpKey].panX + action.dx,
 52→          panY: state[vpKey].panY + action.dy,
 53→        },
 54→      };
 55→    }
 56→
 57→    case 'ZOOM': {
 58→      const { zoom, panX, panY } = action;
 59→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 60→      return {
 61→        ...state,
 62→        [vpKey]: { zoom, panX, panY },
 63→      };
 64→    }
 65→
 66→    case 'SET_WORKSPACE_MODE':
 67→      return {
 68→        ...state,
 69→        workspaceMode: action.workspaceMode,
 70→        selectedId: null,
 71→        selectedType: null,
 72→      };
 73→
 74→    case 'SET_ACTIVE_SHEET':
 75→      return {
 76→        ...state,
 77→        activeSheetId: action.sheetId,
 78→        selectedId: null,
 79→        selectedType: null,
 80→      };
 81→
 82→    case 'SET_VIEW':
 83→      return {
 84→        ...state,
 85→        activeView: action.view,
 86→      };
 87→
 88→    case 'SET_ACTIVE_ASSEMBLY':
 89→      return {
 90→        ...state,
 91→        activeAssemblyId: action.assemblyId,
 92→      };
 93→
 94→    case 'TOGGLE_GRID':
 95→      return { ...state, showGrid: !state.showGrid };
 96→
 97→    case 'TOGGLE_SNAP':
 98→      return { ...state, snapEnabled: !state.snapEnabled };
 99→
100→    case 'SET_STATUS_MESSAGE':
101→      return { ...state, statusMessage: action.message };
102→
103→    case 'CLEAR_STATUS_MESSAGE':
104→      if (!state.statusMessage) return state;
105→      return { ...state, statusMessage: null };
106→
107→    case 'DISMISS_EMPTY_STATE':
108→      return { ...state, emptyStateDismissed: true };
109→
110→    case 'TOGGLE_MAXIMIZE_PANEL':
111→      return { ...state, maximizedPanel: state.maximizedPanel === action.panel ? null : action.panel };
112→
113→    default:
114→      return state;
115→  }
116→}
