138→function DimensionFields({ part, onUpdate, dispatch, project }) {
139→  const measurement = Math.round(
140→    Math.sqrt(
141→      Math.pow((part.endPoint?.x || 0) - (part.startPoint?.x || 0), 2) +
142→      Math.pow((part.endPoint?.y || 0) - (part.startPoint?.y || 0), 2) +
143→      Math.pow((part.endPoint?.z || 0) - (part.startPoint?.z || 0), 2)
144→    )
145→  );
146→
147→  const handleBoundValueChange = (newVal) => {
148→    if (!part.boundPartId || !part.boundProperty) return;
149→    const boundPart = project.parts.find((p) => p.id === part.boundPartId);
150→    if (!boundPart) return;
151→    const result = applyDimensionValueToPart(part, newVal, boundPart);
152→    if (result) {
153→      dispatch({ type: 'PART_UPDATE', part: { id: result.partId, ...result.changes } });
154→    }
155→  };
156→
157→  const bindableParts = project.parts.filter((p) => p.type !== 'dimension');
158→
159→  const BINDABLE_PROPS = {
160→    panel: ['width', 'depth', 'thickness'],
161→    leg: ['width', 'depth', 'height'],
162→    frame: ['width', 'height', 'length'],
163→    cutout: ['width', 'height', 'depth'],
164→    hole: ['diameter', 'depth'],
165→  };
166→
167→  const handleBind = (partId, property) => {
168→    const target = project.parts.find((p) => p.id === partId);
169→    if (!target) return;
170→    const updated = bindDimensionToPart(part, target, property);
171→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...updated } });
172→  };
173→
174→  return (
175→    <>
176→      {part.boundPartId ? (
177→        <NumberInput
178→          label="Value"
179→          value={measurement}
180→          suffix="mm"
181→          onChange={handleBoundValueChange}
182→        />
183→      ) : (
184→        <NumberInput label="Measured" value={measurement} readOnly suffix="mm" onChange={() => {}} />
185→      )}
186→      <NumberInput label="Offset" value={part.offset || 200} onChange={(v) => onUpdate({ offset: v })} />
187→      <TextInput label="Text Override" value={part.textOverride || ''} onChange={(v) => onUpdate({ textOverride: v || null })} />
188→      {part.boundPartId && (
189→        <div className={styles.field}>
190→          <span className={styles.fieldLabel}>Bound to</span>
191→          <span className={styles.typeBadge}>{part.boundProperty || 'part'}</span>
192→        </div>
193→      )}
194→      {!part.boundPartId && bindableParts.length > 0 && (
195→        <BindDimensionUI parts={bindableParts} bindableProps={BINDABLE_PROPS} onBind={handleBind} />
196→      )}
197→    </>
198→  );
199→}
