201→function BindDimensionUI({ parts, bindableProps, onBind }) {
202→  const [selectedPartId, setSelectedPartId] = useState('');
203→  const [selectedProp, setSelectedProp] = useState('');
204→
205→  const selectedPart = parts.find((p) => p.id === selectedPartId);
206→  const props = selectedPart ? (bindableProps[selectedPart.type] || []) : [];
207→
208→  return (
209→    <div className={styles.fieldGroup}>
210→      <span className={styles.groupTitle}>Bind to Part</span>
211→      <select
212→        className={styles.selectInput}
213→        value={selectedPartId}
214→        onChange={(e) => { setSelectedPartId(e.target.value); setSelectedProp(''); }}
215→      >
216→        <option value="">Select part...</option>
217→        {parts.map((p) => (
218→          <option key={p.id} value={p.id}>{p.name} ({p.type})</option>
219→        ))}
220→      </select>
221→      {props.length > 0 && (
222→        <select
223→          className={styles.selectInput}
224→          value={selectedProp}
225→          onChange={(e) => setSelectedProp(e.target.value)}
226→        >
227→          <option value="">Select property...</option>
228→          {props.map((pr) => (
229→            <option key={pr} value={pr}>{pr}</option>
230→          ))}
231→        </select>
232→      )}
233→      {selectedPartId && selectedProp && (
234→        <button
235→          className={styles.duplicateBtn}
236→          onClick={() => onBind(selectedPartId, selectedProp)}
237→        >
238→          Bind
239→        </button>
240→      )}
241→    </div>
242→  );
243→}
