373→function SheetViewportProperties({ viewport, sheet, project, dispatch }) {
374→  const assemblies = project.assemblies || [];
375→  const selectableParts = project.parts.filter((p) => p.type !== 'dimension');
376→
377→  const handleUpdate = (changes) => {
378→    dispatch({
379→      type: 'SKETCH_SHEET_VIEWPORT_UPDATE',
