file.content:
.sidebar {
  background: var(--color-panel-bg);
  border-right: 1px solid var(--color-border);
  overflow-y: auto;
  padding: var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.section {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.sectionHeaderRow {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 2px 4px;
  border-bottom: 1px solid var(--color-workspace-sketch, #B8860B);
  padding-bottom: 6px;
}

.sectionTitle {
  font-family: var(--font-heading);
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--color-text-primary);
}

.count {
  margin-left: auto;
  font-size: 10px;
  color: var(--color-workspace-sketch, #B8860B);
  background: rgba(184, 134, 11, 0.1);
  padding: 0 5px;
  border-radius: 10px;
  line-height: 18px;
  font-weight: 700;
}

.addBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  border-radius: var(--radius-sm);
  color: var(--color-text-secondary);
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  background: transparent;
  border: none;
  transition: background var(--duration-fast), color var(--duration-fast);
  flex-shrink: 0;
}

.addBtn:hover {
  background: rgba(0, 0, 0, 0.06);
  color: var(--color-workspace-sketch, #B8860B);
}

.addBtn:active {
  transform: scale(0.92);
}

.layerList {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.layerItem {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 8px;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: background var(--duration-fast);
  border: 1px solid transparent;
}

.layerItem:hover {
  background: rgba(0, 0, 0, 0.03);
}

.layerItemActive {
  background: rgba(184, 134, 11, 0.08);
  border-color: rgba(184, 134, 11, 0.2);
}

.layerItemActive:hover {
  background: rgba(184, 134, 11, 0.12);
}

.layerInfo {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
  flex: 1;
}

.layerName {
  font-family: var(--font-ui);
  font-size: 12px;
  font-weight: 500;
  color: var(--color-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.shapeCount {
  font-size: 10px;
  color: var(--color-text-tertiary);
  background: rgba(0, 0, 0, 0.04);
  padding: 0 4px;
  border-radius: 8px;
  line-height: 16px;
  flex-shrink: 0;
}

.layerActions {
  display: flex;
  align-items: center;
  gap: 2px;
  flex-shrink: 0;
  opacity: 0.5;
  transition: opacity var(--duration-fast);
}

.layerItem:hover .layerActions {
  opacity: 1;
}

.layerItemActive .layerActions {
  opacity: 0.8;
}

.layerActionBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  border-radius: var(--radius-sm);
  background: transparent;
  border: none;
  color: var(--color-text-secondary);
  cursor: pointer;
  transition: background var(--duration-fast), color var(--duration-fast);
}

.layerActionBtn:hover {
  background: rgba(0, 0, 0, 0.06);
  color: var(--color-text-primary);
}

.layerActionBtn:active {
  transform: scale(0.9);
}

.layerActionBtn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

.layerActionBtn:disabled:hover {
  background: transparent;
  color: var(--color-text-secondary);
}

.layerActionIcon {
  width: 14px;
  height: 14px;
  display: block;
}

.categoryBadge {
  font-size: 9px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--color-workspace-sketch, #B8860B);
  background: rgba(184, 134, 11, 0.1);
  padding: 1px 5px;
  border-radius: 8px;
  line-height: 16px;
  flex-shrink: 0;
}

.indent {
  padding-left: 8px;
}

.expandBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  border: none;
  background: transparent;
  cursor: pointer;
  padding: 0;
  flex-shrink: 0;
  color: var(--color-text-secondary);
}

.expandBtn:hover {
  color: var(--color-text-primary);
}

.expandToggle {
  transition: transform var(--duration-fast);
}

