input.content:
import { createPanel } from '../partModels';

const cabinetTemplate = {
  type: 'cabinet',
  label: 'Cabinet',
  description: 'Box with sides, shelves, optional doors and back',
  parameters: [
    { key: 'width', label: 'Width', type: 'number', default: 600, min: 200, max: 3000, step: 10, suffix: 'mm' },
    { key: 'depth', label: 'Depth', type: 'number', default: 400, min: 150, max: 1500, step: 10, suffix: 'mm' },
    { key: 'height', label: 'Height', type: 'number', default: 800, min: 200, max: 3000, step: 10, suffix: 'mm' },
    { key: 'panelThickness', label: 'Panel Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
    { key: 'shelfCount', label: 'Shelves', type: 'integer', default: 2, min: 0, max: 10, step: 1, suffix: '' },
    { key: 'hasDoors', label: 'Doors', type: 'boolean', default: false },
    { key: 'hasBack', label: 'Back Panel', type: 'boolean', default: true },
  ],
  generate(params) {
    const { width, depth, height, panelThickness, shelfCount, hasDoors, hasBack } = params;
    const innerWidth = width - 2 * panelThickness;
    const innerHeight = height - 2 * panelThickness;
    const parts = [];

    // Left side panel (vertical)
    parts.push(createPanel({
      name: 'Left Side',
      width: panelThickness,
      depth,
      thickness: innerHeight,
      material: 'plywood',
      position: { x: 0, y: 0, z: panelThickness },
    }));

    // Right side panel (vertical)
    parts.push(createPanel({
      name: 'Right Side',
      width: panelThickness,
      depth,
      thickness: innerHeight,
      material: 'plywood',
      position: { x: width - panelThickness, y: 0, z: panelThickness },
    }));

    // Bottom panel
    parts.push(createPanel({
      name: 'Bottom',
      width: innerWidth,
      depth,
      thickness: panelThickness,
      material: 'plywood',
      position: { x: panelThickness, y: 0, z: 0 },
    }));

    // Top panel
    parts.push(createPanel({
      name: 'Top',
      width: innerWidth,
      depth,
      thickness: panelThickness,
      material: 'plywood',
      position: { x: panelThickness, y: 0, z: height - panelThickness },
    }));

    // Shelves
    if (shelfCount > 0) {
      const spacing = innerHeight / (shelfCount + 1);
      for (let i = 1; i <= shelfCount; i++) {
        const z = panelThickness + spacing * i - panelThickness / 2;
        parts.push(createPanel({
          name: `Shelf ${i}`,
          width: innerWidth,
          depth,
          thickness: panelThickness,
          material: 'plywood',
          position: { x: panelThickness, y: 0, z },
        }));
      }
    }

    // Optional back panel
    if (hasBack) {
      parts.push(createPanel({
        name: 'Back',
        width,
        depth: panelThickness,
        thickness: height,
        material: 'plywood',
        position: { x: 0, y: depth - panelThickness, z: 0 },
        fill: 'rgba(120, 120, 120, 0.06)',
      }));
    }

    // Optional doors
    if (hasDoors) {
      const doorWidth = innerWidth / 2;
      parts.push(createPanel({
        name: 'Left Door',
        width: doorWidth,
        depth: panelThickness,
        thickness: innerHeight,
        material: 'plywood',
        position: { x: panelThickness, y: 0, z: panelThickness },
        fill: 'rgba(184, 134, 11, 0.1)',
      }));
      parts.push(createPanel({
        name: 'Right Door',
        width: doorWidth,
        depth: panelThickness,
        thickness: innerHeight,
        material: 'plywood',
        position: { x: panelThickness + doorWidth, y: 0, z: panelThickness },
        fill: 'rgba(184, 134, 11, 0.1)',
      }));
    }

    return {
      parts,
      name: `Cabinet ${width}×${depth}×${height}`,
    };
  },
};

export default cabinetTemplate;

