  panel: '#B8860B',
  leg: '#6B8E23',
  frame: '#4682B4',
  cutout: '#CD5C5C',
  hole: '#9370DB',
  dimension: '#708090',
};

function TypeBadge({ type }) {
  const color = PART_TYPE_COLORS[type] || '#666';
