                      background: 'var(--color-panel-bg)', cursor: 'pointer', fontSize: '12px', color: 'var(--color-text-secondary)',
                    }}
                  >
                    Delete
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </Modal>
  );
