152→export function useSketchEditor() {
153→  const ctx = useContext(SketchEditorContext);
154→  if (!ctx) throw new Error('useSketchEditor must be used within SketchEditorProvider');
155→  const { state } = ctx;
156→  const viewport = state.workspaceMode === 'sheet' ? state.sheetViewport : state.modelViewport;
157→  return { ...state, viewport, dispatch: ctx.dispatch };
158→}
