  1→import { useRef, useEffect, useCallback, useMemo, useState } from 'react';
  2→import * as THREE from 'three';
  3→import { useSketch } from '../app/SketchProvider';
  4→import { useSketchEditor } from '../app/SketchEditorProvider';
  5→import { buildSketchPreviewRoot } from './buildSketchPreview';
  6→import { getSketchPartInspection } from './sketchPreviewInspection';
  7→import { createPreviewViewport } from '@/three/viewer/createPreviewViewport';
  8→import { disposeScene } from '@/three/viewer/disposeScene';
  9→import CompassOverlay from '@/ui/CompassOverlay';
 10→import { ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 11→import styles from './SketchPreviewPanel.module.css';
 12→
 13→export default function SketchPreviewPanel({ isMaximized = false, onToggleMaximize, className = '' }) {
 14→  const containerRef = useRef(null);
 15→  const viewportRef = useRef(null);
 16→  const rootRef = useRef(null);
 17→  const resizeObserverRef = useRef(null);
 18→  const compassNeedleRef = useRef(null);
 19→
 20→  const [navigationMode, setNavigationMode] = useState('inspect');
 21→  const [walkUiState, setWalkUiState] = useState({
 22→    navigationMode: 'inspect',
 23→    isLocked: false,
 24→    canLock: false,
 25→  });
 26→  const [previewScope, setPreviewScope] = useState('all');
 27→
 28→  const { project } = useSketch();
 29→  const { selectedId, dispatch: editorDispatch } = useSketchEditor();
 30→
 31→  const visibleParts = useMemo(() => {
 32→    const renderable = project.parts.filter(
 33→      (p) => p.type !== 'dimension' && p.type !== 'cutout' && p.type !== 'hole'
 34→    );
 35→    if (previewScope === 'all') return renderable;
 36→    return renderable.filter((p) => p.assemblyId === previewScope);
 37→  }, [project.parts, previewScope]);
 38→
 39→  const inspection = useMemo(
 40→    () => getSketchPartInspection(project, selectedId),
 41→    [project, selectedId]
 42→  );
 43→
 44→  const handlePreviewPick = useCallback((target) => {
 45→    if (!target?.sourceId || !target?.kind) {
 46→      editorDispatch({ type: 'DESELECT' });
 47→      return;
 48→    }
 49→    editorDispatch({ type: 'SELECT_OBJECT', id: target.sourceId, objectType: target.kind });
 50→  }, [editorDispatch]);
 51→
 52→  // Initialize viewport
 53→  useEffect(() => {
 54→    const container = containerRef.current;
 55→    if (!container) return;
 56→
 57→    const viewport = createPreviewViewport(container);
 58→    viewportRef.current = viewport;
 59→
 60→    if ('ResizeObserver' in window) {
 61→      const observer = new ResizeObserver(() => viewport.resize());
 62→      observer.observe(container);
 63→      resizeObserverRef.current = observer;
 64→    }
 65→
 66→    viewport.resize();
 67→
 68→    return () => {
 69→      resizeObserverRef.current?.disconnect?.();
 70→      resizeObserverRef.current = null;
 71→      if (rootRef.current) {
 72→        disposeScene(rootRef.current, { disposeMaterials: true });
 73→        rootRef.current = null;
 74→      }
 75→      viewport.dispose();
 76→      viewportRef.current = null;
 77→    };
 78→  }, []);
 79→
 80→  // Pick handler
 81→  useEffect(() => {
 82→    viewportRef.current?.setPickHandler(handlePreviewPick);
 83→  }, [handlePreviewPick]);
 84→
 85→  // Walk UI handlers
 86→  useEffect(() => {
 87→    viewportRef.current?.setWalkUiHandler(setWalkUiState);
 88→    viewportRef.current?.setWalkExitHandler(() => {
 89→      setNavigationMode('inspect');
 90→    });
 91→  }, []);
 92→
 93→  // Compass heading
 94→  useEffect(() => {
 95→    viewportRef.current?.setCompassHeadingHandler((headingDeg) => {
 96→      if (!compassNeedleRef.current) return;
 97→      compassNeedleRef.current.style.setProperty('--compass-heading', `${headingDeg}deg`);
 98→    });
 99→
100→    return () => {
101→      viewportRef.current?.setCompassHeadingHandler(null);
102→    };
103→  }, []);
104→
105→  // Update scene when parts change
106→  useEffect(() => {
107→    const viewport = viewportRef.current;
108→    if (!viewport) return;
109→
110→    // Dispose old root
111→    if (rootRef.current) {
112→      disposeScene(rootRef.current, { disposeMaterials: true });
113→    }
114→
115→    const root = buildSketchPreviewRoot(visibleParts, selectedId);
116→    rootRef.current = root;
117→
118→    // Compute bounds from parts
119→    const box = new THREE.Box3();
120→    root.updateMatrixWorld(true);
121→    box.expandByObject(root);
122→
123→    if (box.isEmpty()) {
124→      box.set(
125→        new THREE.Vector3(-500, 0, -300),
126→        new THREE.Vector3(500, 800, 300)
127→      );
128→    }
129→
130→    const bounds = {
131→      min: { x: box.min.x, y: box.min.y, z: box.min.z },
132→      max: { x: box.max.x, y: box.max.y, z: box.max.z },
133→    };
134→
135→    viewport.setWorld(root, bounds, 0);
136→  }, [visibleParts, selectedId]);
137→
138→  // Navigation mode
139→  useEffect(() => {
140→    viewportRef.current?.setNavigationMode(navigationMode);
141→  }, [navigationMode]);
142→
143→  // Walk floor context — compute spawn from part bounds
144→  useEffect(() => {
145→    if (navigationMode !== 'walk') return;
146→
147→    const box = new THREE.Box3();
148→    if (rootRef.current) {
149→      rootRef.current.updateMatrixWorld(true);
150→      box.expandByObject(rootRef.current);
151→    }
152→
153→    if (box.isEmpty()) {
154→      box.set(new THREE.Vector3(-500, 0, -300), new THREE.Vector3(500, 800, 300));
155→    }
156→
157→    const center = new THREE.Vector3();
158→    box.getCenter(center);
159→
160→    viewportRef.current?.setActiveFloorContext({
161→      floorId: null,
162→      spawnPoint: { x: center.x, y: box.max.y + 500, z: center.z + 1000 },
163→      floorY: 0,
164→    });
165→  }, [navigationMode, visibleParts]);
166→
167→  const resetLabel = navigationMode === 'walk' ? 'Reset Walk' : 'Reset View';
168→  const primaryFooter = navigationMode === 'walk'
169→    ? (walkUiState.isLocked
170→      ? 'Look: mouse · Fly: W/A/S/D · Up/Down: R/F · Faster: Shift · Exit: Esc'
171→      : 'Walk: click preview to capture mouse · Fly: W/A/S/D · Up/Down: R/F · Faster: Shift · Exit: Esc')
172→    : 'Orbit: drag · Pan: right drag · Zoom: wheel · Inspect: click object';
173→  const secondaryFooter = navigationMode === 'walk'
174→    ? 'Noclip flight mode — collision-free exploration.'
175→    : 'Perspective preview of sketch parts.';
176→
177→  return (
178→    <section className={`${styles.panel} ${className}`}>
179→      <div className={styles.header}>
180→        <div className={styles.titleGroup}>
181→          <span className={styles.eyebrow}>3D Preview</span>
182→          <span className={styles.title}>
183→            {visibleParts.length === 1 ? '1 part' : `${visibleParts.length} parts`}
184→          </span>
185→        </div>
186→        <div className={styles.actions}>
187→          <div className={styles.modeToggle} role="group" aria-label="Preview navigation mode">
188→            <button
189→              type="button"
190→              className={navigationMode === 'inspect' ? styles.modeButtonActive : styles.modeButton}
191→              onClick={() => setNavigationMode('inspect')}
192→              aria-pressed={navigationMode === 'inspect'}
193→            >
194→              Inspect
195→            </button>
196→            <button
197→              type="button"
198→              className={navigationMode === 'walk' ? styles.modeButtonActive : styles.modeButton}
199→              onClick={() => setNavigationMode('walk')}
200→              aria-pressed={navigationMode === 'walk'}
201→            >
202→              Walk
203→            </button>
204→          </div>
205→          <select
206→            className={styles.assemblySelect}
207→            value={previewScope}
208→            onChange={(e) => setPreviewScope(e.target.value)}
209→          >
210→            <option value="all">All Parts</option>
211→            {project.assemblies.map((asm) => (
212→              <option key={asm.id} value={asm.id}>{asm.name}</option>
213→            ))}
214→          </select>
215→          <button
216→            type="button"
217→            className={styles.button}
218→            onClick={() => viewportRef.current?.resetView()}
219→          >
220→            {resetLabel}
221→          </button>
