139→export default function SketchSidebar() {
140→  const { project, dispatch, getPartsForAssembly } = useSketch();
141→  const { activeAssemblyId, selectedId, selectedType, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
142→  const { setShowTemplateDialog } = useSketchProject();
143→
144→  const [expandedIds, setExpandedIds] = useState(new Set());
145→
146→  const assemblies = project.assemblies || [];
147→  const allParts = project.parts.filter((p) => p.type !== 'dimension');
148→
149→  // Build part tree: group by assembly, then nest children under parents
150→  const toggleExpand = (id) => {
151→    setExpandedIds((prev) => {
152→      const next = new Set(prev);
153→      if (next.has(id)) next.delete(id);
154→      else next.add(id);
155→      return next;
156→    });
157→  };
158→
159→  const handleAddAssembly = () => {
160→    const asm = createAssembly(`Assembly ${assemblies.length + 1}`);
161→    dispatch({ type: 'ASSEMBLY_ADD', assembly: asm });
162→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: asm.id });
163→  };
164→
165→  const handleSelectAssembly = (assemblyId) => {
166→    if (workspaceMode === 'sheet') {
167→      editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
168→    }
169→    const toggling = activeAssemblyId === assemblyId;
170→    editorDispatch({
171→      type: 'SET_ACTIVE_ASSEMBLY',
172→      assemblyId: toggling ? null : assemblyId,
173→    });
174→    if (!toggling) {
175→      editorDispatch({ type: 'SELECT_OBJECT', id: assemblyId, objectType: 'assembly' });
176→    } else {
177→      editorDispatch({ type: 'DESELECT' });
178→    }
179→  };
180→
181→  const handleDeleteAssembly = (e, assemblyId) => {
182→    e.stopPropagation();
183→    dispatch({ type: 'ASSEMBLY_DELETE', assemblyId });
184→    if (activeAssemblyId === assemblyId) {
185→      editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
186→    }
187→  };
188→
189→  const handleCloneAssembly = (e, assemblyId) => {
190→    e.stopPropagation();
191→    dispatch({ type: 'ASSEMBLY_CLONE', assemblyId });
192→  };
193→
194→  const handleSelectPart = (partId) => {
195→    if (workspaceMode === 'sheet') {
196→      editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
197→    }
198→    editorDispatch({ type: 'SELECT_OBJECT', id: partId, objectType: 'part' });
199→  };
200→
201→  const handleDeletePart = (partId) => {
202→    dispatch({ type: 'PART_DELETE', partId });
203→    if (selectedId === partId) {
204→      editorDispatch({ type: 'DESELECT' });
205→    }
206→  };
207→
208→  const handleClonePart = (partId) => {
209→    dispatch({ type: 'PART_CLONE', partId });
210→  };
211→
212→  // Build tree for a given set of parts
213→  function renderPartTree(parts, depth = 0) {
214→    const topLevel = parts.filter((p) => !p.parentId || !parts.some((pp) => pp.id === p.parentId));
215→    return topLevel.map((part) => {
216→      const children = parts.filter((p) => p.parentId === part.id);
217→      return (
218→        <div key={part.id}>
219→          <PartItem
220→            part={part}
221→            isSelected={part.id === selectedId}
222→            depth={depth}
223→            onSelect={handleSelectPart}
224→            onDelete={handleDeletePart}
225→            onClone={handleClonePart}
226→          />
227→          {children.length > 0 && children.map((child) => (
228→            <PartItem
229→              key={child.id}
230→              part={child}
231→              isSelected={child.id === selectedId}
232→              depth={depth + 1}
233→              onSelect={handleSelectPart}
234→              onDelete={handleDeletePart}
235→              onClone={handleClonePart}
236→            />
237→          ))}
238→        </div>
239→      );
240→    });
241→  }
242→
243→  // Unassigned parts: no assemblyId
244→  const unassignedParts = allParts.filter((p) => !p.assemblyId);
245→  const sheets = project.sheets || [];
246→
247→  const handleAddSheet = () => {
248→    const sheet = createSheet(`Sheet ${sheets.length + 1}`, {
249→      number: `S${String(sheets.length + 1).padStart(2, '0')}`,
250→      drawingName: `Sheet ${sheets.length + 1}`,
251→    });
252→    dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
253→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
254→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
255→  };
256→
257→  const handleSelectSheet = (sheetId) => {
258→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId });
259→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
260→  };
261→
262→  const handleDeleteSheet = (e, sheetId) => {
263→    e.stopPropagation();
264→    dispatch({ type: 'SKETCH_SHEET_DELETE', sheetId });
265→    if (activeSheetId === sheetId) {
266→      editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
267→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
268→    }
269→  };
270→
271→  const handleGenerateAssemblySheet = (e, assemblyId) => {
272→    e.stopPropagation();
273→    const sheet = generateAssemblySheet(project, assemblyId);
274→    dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
275→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
276→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
277→  };
278→
279→  return (
280→    <div className={styles.sidebar}>
281→      {/* Assemblies panel */}
282→      <div className={styles.section}>
283→        <div className={styles.sectionHeaderRow}>
284→          <span className={styles.sectionTitle}>Assemblies</span>
285→          <span className={styles.count}>{assemblies.length}</span>
286→          <button className={styles.addBtn} onClick={() => setShowTemplateDialog(true)} aria-label="Create from Template" title="Create from Template">
287→            <TemplateIcon />
288→          </button>
289→          <button className={styles.addBtn} onClick={handleAddAssembly} aria-label="Add Assembly" title="Add Assembly">+</button>
290→        </div>
291→
292→        <div className={styles.layerList}>
293→          {assemblies.map((asm) => {
294→            const isActive = asm.id === activeAssemblyId;
295→            const isExpanded = expandedIds.has(asm.id);
296→            const asmParts = allParts.filter((p) => p.assemblyId === asm.id);
297→            const partCount = asmParts.length;
298→
299→            return (
300→              <div key={asm.id}>
301→                <div
302→                  className={`${styles.layerItem} ${isActive ? styles.layerItemActive : ''}`}
303→                  onClick={() => handleSelectAssembly(asm.id)}
304→                  role="button"
305→                  tabIndex={0}
306→                  onKeyDown={(e) => {
307→                    if (e.key === 'Enter' || e.key === ' ') {
308→                      e.preventDefault();
309→                      handleSelectAssembly(asm.id);
310→                    }
311→                  }}
312→                >
313→                  <div className={styles.layerInfo}>
314→                    <button
315→                      className={styles.expandBtn}
316→                      onClick={(e) => { e.stopPropagation(); toggleExpand(asm.id); }}
317→                      aria-label={isExpanded ? 'Collapse' : 'Expand'}
318→                    >
319→                      <ChevronIcon expanded={isExpanded} />
320→                    </button>
321→                    <AssemblyIcon />
322→                    <span className={styles.layerName}>{asm.name}</span>
323→                    {asm.templateType && (
324→                      <span className={styles.categoryBadge} style={{ color: '#4682B4', background: '#4682B422', borderColor: '#4682B444' }}>
325→                        {asm.templateType}
326→                      </span>
327→                    )}
328→                    {partCount > 0 && <span className={styles.shapeCount}>{partCount}</span>}
329→                  </div>
330→                  <div className={styles.layerActions}>
331→                    <button
332→                      className={styles.layerActionBtn}
333→                      onClick={(e) => handleGenerateAssemblySheet(e, asm.id)}
334→                      aria-label="Generate Assembly Sheet"
335→                      title="Generate Assembly Sheet"
336→                    >
337→                      <SheetIcon />
338→                    </button>
339→                    <button
340→                      className={styles.layerActionBtn}
341→                      onClick={(e) => handleCloneAssembly(e, asm.id)}
342→                      aria-label="Duplicate Assembly"
343→                      title="Duplicate Assembly"
344→                    >
345→                      <CloneIcon />
346→                    </button>
347→                    <button
348→                      className={styles.layerActionBtn}
349→                      onClick={(e) => handleDeleteAssembly(e, asm.id)}
350→                      aria-label="Delete Assembly"
351→                      title="Delete Assembly"
352→                    >
353→                      <TrashIcon />
354→                    </button>
355→                  </div>
356→                </div>
357→
358→                {/* Expanded: show nested parts */}
359→                {isExpanded && asmParts.length > 0 && (
360→                  <div className={styles.indent}>
361→                    {renderPartTree(asmParts, 1)}
362→                  </div>
363→                )}
364→              </div>
365→            );
366→          })}
367→        </div>
368→      </div>
369→
370→      {/* Unassigned Parts */}
371→      <div className={styles.section}>
372→        <div className={styles.sectionHeaderRow}>
373→          <span className={styles.sectionTitle}>
374→            Unassigned Parts
375→          </span>
376→          <span className={styles.count}>{unassignedParts.length}</span>
377→        </div>
378→
379→        <div className={styles.layerList}>
380→          {renderPartTree(unassignedParts, 0)}
381→        </div>
382→      </div>
383→
384→      {/* Sheets */}
385→      <div className={styles.section}>
386→        <div className={styles.sectionHeaderRow}>
387→          <span className={styles.sectionTitle}>Sheets</span>
388→          <span className={styles.count}>{sheets.length}</span>
389→          <button className={styles.addBtn} onClick={handleAddSheet} aria-label="Add Sheet" title="Add Sheet">+</button>
390→        </div>
391→
392→        <div className={styles.layerList}>
393→          {sheets.map((sheet) => {
394→            const isActive = workspaceMode === 'sheet' && activeSheetId === sheet.id;
395→            return (
396→              <div
397→                key={sheet.id}
398→                className={`${styles.layerItem} ${isActive ? styles.layerItemActive : ''}`}
399→                onClick={() => handleSelectSheet(sheet.id)}
400→                role="button"
401→                tabIndex={0}
402→                onKeyDown={(e) => {
403→                  if (e.key === 'Enter' || e.key === ' ') {
404→                    e.preventDefault();
405→                    handleSelectSheet(sheet.id);
406→                  }
407→                }}
408→              >
409→                <div className={styles.layerInfo}>
410→                  <SheetIcon />
411→                  <span className={styles.layerName}>{sheet.title || sheet.drawingName || 'Sheet'}</span>
412→                  {(sheet.viewports || []).length > 0 && (
413→                    <span className={styles.shapeCount}>{sheet.viewports.length}v</span>
414→                  )}
415→                </div>
416→                <div className={styles.layerActions}>
417→                  <button
418→                    className={styles.layerActionBtn}
419→                    onClick={(e) => handleDeleteSheet(e, sheet.id)}
420→                    aria-label="Delete Sheet"
421→                    title="Delete Sheet"
422→                  >
423→                    <TrashIcon />
424→                  </button>
425→                </div>
426→              </div>
427→            );
428→          })}
429→        </div>
430→      </div>
431→    </div>
432→  );
433→}
