247→function ConstraintsSection({ part, project, dispatch }) {
248→  const [showForm, setShowForm] = useState(false);
249→  const [cType, setCType] = useState('attach_face');
250→  const [targetId, setTargetId] = useState('');
251→  const [srcAnchor, setSrcAnchor] = useState('bottom');
252→  const [tgtAnchor, setTgtAnchor] = useState('top');
253→  const [offset, setOffset] = useState(0);
254→
255→  const constraints = (project.constraints || []).filter(
256→    (c) => c.sourcePartId === part.id || c.targetPartId === part.id
