259→  const otherParts = project.parts.filter((p) => p.id !== part.id && p.type !== 'dimension');
260→
261→  const handleAddConstraint = () => {
262→    if (!targetId) return;
263→    const constraint = createConstraint({
264→      type: cType,
265→      sourcePartId: part.id,
266→      targetPartId: targetId,
267→      sourceAnchor: srcAnchor,
268→      targetAnchor: tgtAnchor,
269→      offset: parseFloat(offset) || 0,
270→    });
271→    dispatch({ type: 'CONSTRAINT_ADD', constraint });
272→    setShowForm(false);
273→    setTargetId('');
274→  };
275→
276→  return (
277→    <div className={styles.fieldGroup}>
278→      <span className={styles.groupTitle}>Constraints</span>
279→      <div className={styles.constraintSection}>
280→        {constraints.map((c) => {
281→          const targetPart = project.parts.find((p) => p.id === (c.sourcePartId === part.id ? c.targetPartId : c.sourcePartId));
282→          return (
283→            <div key={c.id} className={styles.constraintItem}>
284→              <span>{c.type}: {c.sourceAnchor} → {c.targetAnchor} ({targetPart?.name || '?'})</span>
285→              <button
286→                className={styles.constraintDelete}
287→                onClick={() => dispatch({ type: 'CONSTRAINT_DELETE', constraintId: c.id })}
288→                title="Remove constraint"
289→              >
