316→          <div style={{ display: 'flex', gap: '4px' }}>
317→            <button className={styles.duplicateBtn} onClick={handleAddConstraint}>Create</button>
318→            <button className={styles.duplicateBtn} onClick={() => setShowForm(false)}>Cancel</button>
319→          </div>
320→        </div>
321→      )}
322→    </div>
323→  );
