file.content:
.toolbar {
  display: flex;
  align-items: center;
  min-height: var(--toolbar-height);
  background: var(--color-panel-bg);
  box-shadow: var(--shadow-toolbar);
  padding: 0 var(--space-md);
  gap: var(--space-sm);
  overflow-x: auto;
  overflow-y: hidden;
  scrollbar-width: thin;
}

.toolbar::-webkit-scrollbar {
  height: 3px;
}
.toolbar::-webkit-scrollbar-thumb {
  background: rgba(0, 0, 0, 0.10);
  border-radius: 2px;
}
.toolbar::-webkit-scrollbar-track {
  background: transparent;
}

.group {
  display: flex;
  align-items: center;
  gap: 2px;
  padding: var(--space-xs) var(--space-sm);
  background: rgba(0, 0, 0, 0.02);
  border-radius: var(--radius-md);
  flex-shrink: 0;
}

.divider {
  width: 1px;
  height: 20px;
  background: linear-gradient(180deg, transparent, rgba(0, 0, 0, 0.08), transparent);
  margin: 0 var(--space-xs);
  flex-shrink: 0;
}

.groupLabel {
  font-family: var(--font-heading);
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--color-text-secondary);
  white-space: nowrap;
  margin-right: 4px;
}

.btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  padding: 0;
  border-radius: var(--radius-sm);
  border: 1px solid transparent;
  color: var(--color-text-secondary);
  box-shadow: inset 0 -1px 0 rgba(0, 0, 0, 0.04);
  transition: background var(--duration-fast), color var(--duration-fast),
    border-color var(--duration-fast), transform var(--duration-micro) var(--ease-tactile),
    box-shadow var(--duration-fast);
  cursor: pointer;
  background: transparent;
}

.btn:hover {
  background: rgba(0, 0, 0, 0.04);
  border-color: rgba(0, 0, 0, 0.06);
  color: var(--color-text-primary);
  transform: translateY(-1px);
  box-shadow: var(--shadow-hover);
}

.btn:active {
  transform: scale(0.97);
  box-shadow: var(--shadow-pressed);
}

.btn:disabled {
  opacity: 0.35;
  cursor: not-allowed;
}

.btn:disabled:hover {
  background: transparent;
  border-color: transparent;
  color: var(--color-text-secondary);
  transform: none;
  box-shadow: inset 0 -1px 0 rgba(0, 0, 0, 0.04);
}

.icon {
  width: 18px;
  height: 18px;
  display: block;
}

.toolPalette {
  display: flex;
  align-items: center;
  gap: 1px;
  padding: var(--space-xs) var(--space-sm);
  background: rgba(0, 0, 0, 0.02);
  border-radius: var(--radius-md);
  flex-shrink: 0;
}

.toolBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 34px;
  height: 34px;
  border-radius: var(--radius-sm);
  border: 1px solid transparent;
  color: var(--color-text-secondary);
  background: transparent;
  cursor: pointer;
  transition: background var(--duration-fast), color var(--duration-fast),
    border-color var(--duration-fast), transform var(--duration-micro) var(--ease-tactile),
    box-shadow var(--duration-fast);
}

.toolBtn:hover {
  background: rgba(0, 0, 0, 0.04);
  border-color: rgba(0, 0, 0, 0.06);
  color: var(--color-text-primary);
  transform: translateY(-1px);
  box-shadow: var(--shadow-sm);
}

.toolBtn:active {
  transform: scale(0.96);
  box-shadow: var(--shadow-pressed);
}

.toolBtnActive {
  composes: toolBtn;
  background: rgba(184, 134, 11, 0.1);
  color: var(--color-workspace-sketch, #B8860B);
  border-color: rgba(184, 134, 11, 0.25);
  box-shadow: 0 0 0 1px rgba(184, 134, 11, 0.08), 0 1px 3px rgba(184, 134, 11, 0.12);
}

.toolBtnActive:hover {
  background: rgba(184, 134, 11, 0.15);
}

.toolBtnActive:active {
  transform: scale(0.96);
  box-shadow: var(--shadow-pressed);
}

.toolIcon {
  width: 18px;
  height: 18px;
  display: block;
}

.toggleBtn {
  composes: btn;
  opacity: 0.5;
}

.toggleBtn.toggleActive {
  opacity: 1;
  background: rgba(184, 134, 11, 0.1);
  color: var(--color-workspace-sketch, #B8860B);
  border-color: rgba(184, 134, 11, 0.25);
  box-shadow: 0 0 0 1px rgba(184, 134, 11, 0.08), 0 1px 3px rgba(184, 134, 11, 0.12);
}

.toggleBtn.toggleActive:hover {
  background: rgba(184, 134, 11, 0.15);
}

.spacer {
  flex: 1;
}

.dropdown {
  position: absolute;
  top: 100%;
  left: 0;
  z-index: 100;
  min-width: 160px;
  background: var(--color-surface-elevated, #fff);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-lg);
  padding: 4px 0;
  margin-top: 4px;
}

.dropdownItem {
  display: block;
  width: 100%;
  padding: 8px 12px;
  text-align: left;
  font-size: 12px;
  font-family: var(--font-ui);
  color: var(--color-text-primary);
  background: transparent;
  border: none;
  cursor: pointer;
  transition: background var(--duration-fast);
}

.dropdownItem:hover {
  background: rgba(0, 0, 0, 0.04);
}

@media (max-width: 900px) {
  .toolbar {
    gap: var(--space-xs);
    padding: var(--space-xs) var(--space-sm);
  }
  .group {
    padding: 0 var(--space-xs);
  }
  .toolPalette {
    padding: 0 var(--space-xs);
  }
  .groupLabel {
    display: none;
  }
}
